540→        Err(AddProjectNextActionError::InvalidTitle(title_err)) => {
541→            let user_facing = match title_err {
542→                TodoTitleError::Empty => {
543→                    if htmx {
544→                        return Ok(StatusCode::NO_CONTENT.into_response());
545→                    }
546→                    return Ok(Redirect::to(&format!("/projects/{project_id}")).into_response());
